+fn arb_grant_condition() -> impl Strategy<Value = GrantCondition> {
+    prop_oneof![
+        (0..1_000_000u64, 0..1_000_000u64)
+            .prop_map(|(s, e)| GrantCondition::TimeWindow {
+                start_ms: s,
+                end_ms: s + e,
